"use client"

import { useEffect, useMemo, useState } from "react"
import { generateSearchIndex } from "@/lib/docs/docs.search"
import { useRouter } from "next/navigation"

export default function DocsSearch() {
  const router = useRouter()

  const [open, setOpen] = useState(false)
  const [query, setQuery] = useState("")

  const searchIndex = useMemo(() => generateSearchIndex(), [])

  const results = query
    ? searchIndex.search(query).slice(0, 8)
    : []

  useEffect(() => {
    const listener = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault()
        setOpen(true)
      }

      if (e.key === "Escape") {
        setOpen(false)
      }
    }

    window.addEventListener("keydown", listener)

    return () => window.removeEventListener("keydown", listener)
  }, [])

  return (
    <>
      <button
        onClick={() => setOpen(true)}
        className="flex items-center gap-2 rounded-md border px-3 py-1.5 text-sm text-muted-foreground hover:bg-muted"
      >
        🔍 Search
        <span className="text-xs opacity-60">⌘K</span>
      </button>

      {open && (
        <div className="fixed inset-0 z-50 flex items-start justify-center bg-black/40 pt-32">
          <div className="w-[600px] rounded-xl bg-background shadow-xl">
            <input
              autoFocus
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search docs..."
              className="w-full border-b px-4 py-3 outline-none"
            />

            <div className="max-h-[400px] overflow-y-auto">
              {results.map((result) => (
                <button
                  key={result.id}
                  onClick={() => {
                    router.push(result.slug)
                    setOpen(false)
                    setQuery("")
                  }}
                  className="block w-full px-4 py-3 text-left hover:bg-muted"
                >
                  <div className="text-sm font-medium">{result.title}</div>
                  <div className="text-xs text-muted-foreground">
                    {result.section}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}
    </>
  )
}